use std::io::{self, BufRead, BufReader};

struct ConfigData {
    lines: Vec<String>,
}

fn process_inputs(reader: impl BufRead) -> io::Result<ConfigData> {
    let reader = BufReader::new(reader);
    let mut lines_vec = Vec::new();
    for line in reader.lines() {
        match line {
            Ok(l) => lines_vec.push(l),
            Err(e) => return Err(e),
        }
    }
    Ok(ConfigData { lines: lines_vec })
}

fn main() -> io::Result<()> {
    let stdin = io::stdin();
    let result = process_inputs(stdin.lock())?;

    println!("Successfully read {} lines from standard input.", result.lines.len());

    if !result.lines.is_empty() {
        println!("First line processed: {}", &result.lines[0]);
    }

    Ok(())
}

use std::collections::HashMap;

struct JobConfig {
    name: String,
    dependencies: Vec<String>,
    timeout_seconds: u32,
}

fn parse_job_block(text: &str) -> Option<JobConfig> {
    let mut name = None;
    let mut dependencies = Vec::new();
    let mut timeout = None;

    for line in text.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() { continue; }

        if trimmed.starts_with("name:") {
            name = Some(trimmed.split(':').nth(1).unwrap().trim().to_string());
        } else if trimmed.starts_with("depends_on:") {
            let deps_str = &trimmed["depends_on:".len()..];
            dependencies.extend(deps_str.split(',').map(|s| s.trim().to_string()).collect::<Vec<String>>());
        } else if trimmed.starts_with("timeout:") {
            let val_str = &trimmed["timeout:".len()..];
            if let Ok(t) = val_str.trim().parse::<u32>() {
                timeout = Some(t);
            }
        }
    }

    match (name, dependencies.is_empty() && timeout.is_some()) {
        (Some(n), true) => Some(JobConfig { name: n, dependencies: vec![], timeout_seconds: timeout.unwrap() }),
        _ => None,
    }
}

fn main() {
    let config_text = "
name: BuildServicentimeout: 60ndepends_on: InitJob, NetworkCheckn";
    match parse_job_block(config_text) {
        Some(config) => println!("Successfully parsed job: {}", config.name),
        None => println!("Failed to parse job configuration.")
    }
}

